import com.evolveum.midpoint.notifications.api.events.ModelEvent import com.evolveum.midpoint.xml.ns._public.common.common_3.UserType import com.evolveum.midpoint.xml.ns._public.common.common_3.AssignmentType
// Solo eventos de modelo, exitosos, sobre usuarios if (!(event instanceof ModelEvent)) return false if (!event.isSuccess()) return false def fc = event.getFocusContext() if (fc == null) return false if (!UserType.class.isAssignableFrom(fc.getObjectTypeClass())) return false
// ¿El usuario tiene asignado el rol AgenteCallCenter? def user = event.getFocusContext().getObjectNew()?.asObjectable() if (user == null) return false boolean tieneRol = user.getAssignment().any { AssignmentType a -> a.getTargetRef() != null && a.getTargetRef().getOid() == 'a0000000-0000-0000-0000-00000000ca11' } return tieneRol

def user = event.getFocusContext().getObjectNew()?.asObjectable()
def oid = user.getOid()
def nombre = (user.getFullName() != null) ? user.getFullName().getOrig() : user.getName().getOrig()
def correo = (user.getEmailAddress() != null) ? user.getEmailAddress() : ''
// JSON que espera /provision
return groovy.json.JsonOutput.toJson([
    oid    : oid,
    nombre : nombre,
    correo : correo
])

import java.net.http.HttpClient import java.net.http.HttpRequest import java.net.http.HttpResponse import java.net.URI import java.time.Duration
def cuerpo = message.getBody()
def client = HttpClient.newBuilder() .connectTimeout(Duration.ofSeconds(10)) .build()
def request = HttpRequest.newBuilder() .uri(URI.create('http://telesecure_webhook:5000/provision')) .timeout(Duration.ofSeconds(120)) .header('Content-Type', 'application/json') .header('X-Auth-Token', 'e228111abf729700c4934bc2b7e36701b5fc8859419619a5') .POST(HttpRequest.BodyPublishers.ofString(cuerpo)) .build()
def response = client.send(request, HttpResponse.BodyHandlers.ofString()) LOGGER.info('TeleSecure webhook respondió HTTP {} : {}', response.statusCode(), response.body())
if (response.statusCode() >= 400) { throw new RuntimeException('Webhook devolvió error HTTP ' + response.statusCode() + ': ' + response.body()) }
